SELECT * FROM network_traffic_rules
WHERE id = #{id}
  AND customer_id = #{customerId}

SELECT * FROM network_traffic_rules
WHERE customer_id = #{customerId}
ORDER BY priority DESC, created_at DESC

SELECT * FROM network_traffic_rules
WHERE configuration_id = #{configurationId}
  AND customer_id = #{customerId}
ORDER BY priority DESC, created_at DESC

SELECT * FROM network_traffic_rules
WHERE configuration_id = #{configurationId}
  AND customer_id = #{customerId}
  AND enabled = TRUE
ORDER BY priority DESC, created_at DESC

mapper.update:
UPDATE network_traffic_rules
SET enabled = #{enabled}, updated_at = NOW()
WHERE id = #{id}
  AND customer_id = #{customerId}

mapper.delete:
DELETE FROM network_traffic_rules
WHERE id = #{id}
  AND customer_id = #{customerId}

DELETE FROM network_traffic_rules
WHERE customer_id = #{customerId}
  AND created_at < #{beforeDate}

mapper.select:
SELECT
    l.*,
    d.number AS device_number,
    r.rule_name,
    r.rule_type
FROM network_traffic_logs l
LEFT JOIN devices d ON l.device_id = d.id
LEFT JOIN network_traffic_rules r ON l.rule_id = r.id
WHERE l.customer_id = #{customerId}

    AND l.device_id = #{deviceId}


    AND l.action = #{action}


    AND l.domain LIKE CONCAT('%', #{domain}, '%')


    AND l.timestamp >= #{startDate}


    AND l.timestamp <= #{endDate}

ORDER BY l.timestamp DESC
LIMIT 1000

mapper.delete:
DELETE FROM network_traffic_logs
WHERE customer_id = #{customerId}
  AND timestamp < #{beforeDate}

